import scala.xml._
import scala.util.{Try, Success, Failure}
import java.io.StringReader
import javax.xml.parsers.SAXParserFactory
import org.xml.sax.InputSource

case class ConfigurationSettings(
  settings: Map[String, String],
  nested: Map[String, ConfigurationSettings] = Map.empty
)

class ConfigurationParserService {
  
  private val secureParserFactory: SAXParserFactory = {
    val factory = SAXParserFactory.newInstance()
    factory.setFeature("http://xml.org/sax/features/external-general-entities", false)
    factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false)
    factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true)
    factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false)
    factory.setXIncludeAware(false)
    factory.setNamespaceAware(true)
    factory
  }

  def parseConfiguration(xmlString: String): Try[ConfigurationSettings] = {
    Try {
      val loader = new scala.xml.factory.XMLLoader[Elem] {
        override def parser = secureParserFactory.newSAXParser()
      }
      val xml = loader.load(new InputSource(new StringReader(xmlString)))
      extractSettings(xml)
    }
  }

  def parseConfigurationUnsafe(xmlString: String): Try[ConfigurationSettings] = {
    Try {
      val xml = XML.loadString(xmlString)
      extractSettings(xml)
    }
  }

  private def extractSettings(node: Node): ConfigurationSettings = {
    val settings = (node \ "setting").map { setting =>
      val key = (setting \ "@key").text
      val value = (setting \ "@value").headOption
        .map(_.text)
        .getOrElse(setting.text.trim)
      key -> value
    }.toMap

    val properties = (node \ "property").map { prop =>
      val name = (prop \ "@name").text
      val value = (prop \ "@value").headOption
        .map(_.text)
        .getOrElse(prop.text.trim)
      name -> value
    }.toMap

    val nestedConfigs = (node \ "configuration").map { config =>
      val name = (config \ "@name").text
      name -> extractSettings(config)
    }.toMap

    val sections = (node \ "section").map { section =>
      val name = (section \ "@name").text
      name -> extractSettings(section)
    }.toMap

    ConfigurationSettings(
      settings ++ properties,
      nestedConfigs ++ sections
    )
  }

  def parseAndMerge(xmlStrings: Seq[String]): Try[ConfigurationSettings] = {
    Try {
      val configs = xmlStrings.map { xmlString =>
        parseConfiguration(xmlString).get
      }
      mergeConfigurations(configs)
    }
  }

  private def mergeConfigurations(configs: Seq[ConfigurationSettings]): ConfigurationSettings = {
    configs.reduceLeft { (acc, config) =>
      ConfigurationSettings(
        acc.settings ++ config.settings,
        mergeMaps(acc.nested, config.nested)
      )
    }
  }

  private def mergeMaps(
    map1: Map[String, ConfigurationSettings],
    map2: Map[String, ConfigurationSettings]
  ): Map[String, ConfigurationSettings] = {
    val allKeys = map1.keySet ++ map2.keySet
    allKeys.map { key =>
      (map1.get(key), map2.get(key)) match {
        case (Some(v1), Some(v2)) => key -> mergeConfigurations(Seq(v1, v2))
        case (Some(v), None) => key -> v
        case (None, Some(v)) => key -> v
        case (None, None) => key -> ConfigurationSettings(Map.empty)
      }
    }.toMap
  }

  def getSetting(config: ConfigurationSettings, path: String): Option[String] = {
    val parts = path.split('.')
    if (parts.length == 1) {
      config.settings.get(parts.head)
    } else {
      config.nested.get(parts.head).flatMap { nested =>
        getSetting(nested, parts.tail.mkString("."))
      }
    }
  }

  def getAllSettings(config: ConfigurationSettings, prefix: String = ""): Map[String, String] = {
    val currentSettings = config.settings.map { case (k, v) =>
      if (prefix.isEmpty) k -> v else s"$prefix.$k" -> v
    }

    val nestedSettings = config.nested.flatMap { case (name, nested) =>
      val newPrefix = if (prefix.isEmpty) name else s"$prefix.$name"
      getAllSettings(nested, newPrefix)
    }

    currentSettings ++ nestedSettings
  }

  def validateXml(xmlString: String): Try[Boolean] = {
    parseConfiguration(xmlString).map(_ => true)
  }

  def extractByXPath(xmlString: String, xpath: String): Try[Seq[String]] = {
    parseConfiguration(xmlString).map { _ =>
      val xml = {
        val loader = new scala.xml.factory.XMLLoader[Elem] {
          override def parser = secureParserFactory.newSAXParser()
        }
        loader.load(new InputSource(new StringReader(xmlString)))
      }
      
      val parts = xpath.split('/')
      extractNodesByPath(xml, parts.toList)
    }
  }

  private def extractNodesByPath(node: Node, path: List[String]): Seq[String] = {
    path match {
      case Nil => Seq(node.text)
      case head :: tail if head.isEmpty => extractNodesByPath(node, tail)
      case head :: tail =>
        val children = node \ head
        children.flatMap(child => extractNodesByPath(child, tail))
    }
  }

  def parseWithEntityReplacement(xmlString: String, entities: Map[String, String]): Try[ConfigurationSettings] = {
    Try {
      var processedXml = xmlString
      entities.foreach { case (entityName, entityValue) =>
        processedXml = processedXml.replaceAll(s"&$entityName;", entityValue)
      }
      parseConfiguration(processedXml).get
    }
  }

  def toXml(config: ConfigurationSettings): String = {
    val xml = 
      <configuration>
        {config.settings.map { case (key, value) =>
          <setting key={key} value={value}/>
        }}
        {config.nested.map { case (name, nested) =>
          <section name={name}>
            {XML.loadString(toXml(nested)).child}
          </section>
        }}
      </configuration>
    
    new PrettyPrinter(80, 2).format(xml)
  }
}

class ConfigurationAPIService {
  private val parser = new ConfigurationParserService()

  def handleConfigurationRequest(xmlPayload: String): Either[String, ConfigurationSettings] = {
    parser.parseConfiguration(xmlPayload) match {
      case Success(config) => Right(config)
      case Failure(ex) => Left(s"Failed to parse configuration: ${ex.getMessage}")
    }
  }

  def handleGetSetting(xmlPayload: String, settingPath: String): Either[String, String] = {
    parser.parseConfiguration(xmlPayload) match {
      case Success(config) =>
        parser.getSetting(config, settingPath) match {
          case Some(value) => Right(value)
          case None => Left(s"Setting not found: $settingPath")
        }
      case Failure(ex) => Left(s"Failed to parse configuration: ${ex.getMessage}")
    }
  }

  def handleGetAllSettings(xmlPayload: String): Either[String, Map[String, String]] = {
    parser.parseConfiguration(xmlPayload) match {
      case Success(config) => Right(parser.getAllSettings(config))
      case Failure(ex) => Left(s"Failed to parse configuration: ${ex.getMessage}")
    }
  }

  def handleMergeConfigurations(xmlPayloads: Seq[String]): Either[String, ConfigurationSettings] = {
    parser.parseAndMerge(xmlPayloads) match {
      case Success(config) => Right(config)
      case Failure(ex) => Left(s"Failed to merge configurations: ${ex.getMessage}")
    }
  }

  def handleValidateConfiguration(xmlPayload: String): Either[String, Boolean] = {
    parser.validateXml(xmlPayload) match {
      case Success(valid) => Right(valid)
      case Failure(ex) => Left(s"Invalid XML: ${ex.getMessage}")
    }
  }

  def handleExportConfiguration(config: ConfigurationSettings): String = {
    parser.toXml(config)
  }

  def handleConfigurationWithEntities(
    xmlPayload: String, 
    entities: Map[String, String]
  ): Either[String, ConfigurationSettings] = {
    parser.parseWithEntityReplacement(xmlPayload, entities) match {
      case Success(config) => Right(config)
      case Failure(ex) => Left(s"Failed to parse configuration with entities: ${ex.getMessage}")
    }
  }
}

